        setResult(initial, 0);
        return result;
    }

    // return the first endpoint if it is good enough
    double yMin = f.value(min);
    if (Math.abs(yMin) <= functionValueAccuracy) {
        setResult(min, 0);
        return result;
    }

    // return the second endpoint if it is good enough
    double yMax = f.value(max);
    if (Math.abs(yMax) <= functionValueAccuracy) {
        setResult(max, 0);
        return result;
    }

    // check if the initial point brackets the root with either endpoint
    if (yInitial * yMin > 0 && yInitial * yMax > 0) {
        throw new IllegalArgumentException("Function values at endpoints and initial guess do not bracket the root");
